import type { ClientLogShipPayload, ClientLogShipResponse } from '@motivation/shared';
import { API_URL } from '../../config.js';
import { getUnshippedEntries, markShipped } from './client-log-store.js';

const SHIP_TAG = 'push-client-logs';
const BATCH_LIMIT = 100;

export interface ShippingDeps {
    fetch?: typeof fetch;
    apiUrl?: string;
    now?: () => string;
}

export interface ShippingResult {
    accepted: number;
    duplicates: number;
    batches: number;
}

class ClientLogShipError extends Error {
    constructor(readonly status: number, message: string) {
        super(message);
        this.name = 'ClientLogShipError';
    }
}

/**
 * Drains unshipped rows from IndexedDB to the server in batches of up to 100.
 * Marks each accepted row's `shipped_at` so future drains skip it. Throws on
 * any non-2xx response so the caller (SW sync event) can leave the rows
 * unshipped and the browser will re-fire on next connectivity change.
 */
export async function shipPendingClientLogs(deps: ShippingDeps = {}): Promise<ShippingResult> {
    const fetchImpl = deps.fetch ?? fetch.bind(globalThis);
    const apiBase = deps.apiUrl ?? API_URL;
    const now = deps.now ?? (() => Temporal.Now.instant().toString());

    let accepted = 0;
    let duplicates = 0;
    let batches = 0;

    while (true) {
        const batch = await getUnshippedEntries(BATCH_LIMIT);
        if (batch.length === 0) break;

        // All entries written by the same device share the same id/label —
        // group by device_id so we ship one POST per device.
        const byDevice = new Map<string, typeof batch>();
        for (const entry of batch) {
            const list = byDevice.get(entry.device_id) ?? [];
            list.push(entry);
            byDevice.set(entry.device_id, list);
        }

        for (const [deviceId, entries] of byDevice.entries()) {
            const label = entries[0].device_label;
            const payload: ClientLogShipPayload = {
                device_id: deviceId,
                device_label: label,
                entries: entries.map(({ shipped_at: _, ...rest }) => rest),
            };

            const response = await fetchImpl(`${apiBase}/api/client-logs`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });

            if (!response.ok) {
                throw new ClientLogShipError(
                    response.status,
                    `Client log ship failed: ${response.status} ${response.statusText}`,
                );
            }

            const body = (await response.json()) as ClientLogShipResponse;
            await markShipped(entries.map((e) => e.id), now());
            accepted += body.accepted;
            duplicates += body.duplicates;
        }

        batches++;
    }

    return { accepted, duplicates, batches };
}

/**
 * Triggers the browser to fire `sync` on `push-client-logs` as soon as the
 * device has connectivity. Throws if the Service Worker or Background Sync
 * API is unavailable — the feature design (story 090) is fail-loudly here
 * because the app is Chrome-only with secure-origin flags.
 */
export async function requestClientLogSync(): Promise<void> {
    if (typeof navigator === 'undefined' || !navigator.serviceWorker) {
        throw new Error('Service Worker is not available — client logs cannot ship');
    }
    const registration = await navigator.serviceWorker.ready;
    if (!registration.sync) {
        throw new Error('Background Sync API is not available — client logs cannot ship');
    }
    await registration.sync.register(SHIP_TAG);
}

export const CLIENT_LOG_SYNC_TAG = SHIP_TAG;

export interface ShippingAvailability {
    ok: boolean;
    error?: string;
}

/**
 * Read-only check used by the Debug screen to surface "client log shipping
 * is broken" without firing a sync registration. Returns ok:false with a
 * human-readable error when the SW or Background Sync API is missing.
 */
export async function checkClientLogShippingAvailability(): Promise<ShippingAvailability> {
    if (typeof navigator === 'undefined' || !navigator.serviceWorker) {
        return { ok: false, error: 'Service Worker is not available in this context' };
    }
    try {
        const registration = await navigator.serviceWorker.ready;
        if (!registration.sync) {
            return { ok: false, error: 'Background Sync API is not available' };
        }
        return { ok: true };
    } catch (error) {
        return {
            ok: false,
            error: error instanceof Error ? (error.stack ?? error.message) : String(error),
        };
    }
}
