import type { ClientLogEntry, LogsQuery, LogsResponse } from '@motivation/shared';

const DB_NAME = 'motivation-client-logs';
const DB_VERSION = 1;
const STORE = 'entries';
const INDEX_SHIPPED = 'shipped_at';
const INDEX_TIMESTAMP = 'timestamp';
const APP_TIME_ZONE = 'Europe/Amsterdam';
const DEFAULT_QUERY_LIMIT = 500;

/**
 * Internal row stored in IndexedDB. Mirrors `ClientLogEntry` plus a nullable
 * `shipped_at` set when the SW successfully POSTs the row to the server.
 *
 * `shipped_at` is empty string (not null) for unshipped rows so it can be
 * indexed — IndexedDB indexes skip rows whose key resolves to null/undefined.
 */
export interface StoredClientLogEntry extends ClientLogEntry {
    shipped_at: string;
}

let dbPromise: Promise<IDBDatabase> | null = null;

function getDb(): Promise<IDBDatabase> {
    if (!dbPromise) {
        dbPromise = open();
    }
    return dbPromise;
}

function open(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.open(DB_NAME, DB_VERSION);
        req.onupgradeneeded = () => {
            const db = req.result;
            if (!db.objectStoreNames.contains(STORE)) {
                const store = db.createObjectStore(STORE, { keyPath: 'id' });
                store.createIndex(INDEX_SHIPPED, 'shipped_at', { unique: false });
                store.createIndex(INDEX_TIMESTAMP, 'timestamp', { unique: false });
            }
        };
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error ?? new Error('Failed to open client-log IndexedDB'));
    });
}

function awaitTx(tx: IDBTransaction): Promise<void> {
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error ?? new Error('IndexedDB transaction failed'));
        tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
    });
}

export async function appendEntries(entries: ClientLogEntry[]): Promise<void> {
    if (entries.length === 0) return;
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    const store = tx.objectStore(STORE);
    for (const entry of entries) {
        const row: StoredClientLogEntry = { ...entry, shipped_at: '' };
        store.put(row);
    }
    await awaitTx(tx);
}

export async function getUnshippedEntries(limit: number): Promise<StoredClientLogEntry[]> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const index = tx.objectStore(STORE).index(INDEX_SHIPPED);
    const range = IDBKeyRange.only('');
    const out: StoredClientLogEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = index.openCursor(range);
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor || out.length >= limit) {
                resolve(out);
                return;
            }
            out.push(cursor.value as StoredClientLogEntry);
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read unshipped client logs'));
    });
}

export async function markShipped(ids: string[], shippedAt: string): Promise<void> {
    if (ids.length === 0) return;
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    const store = tx.objectStore(STORE);
    for (const id of ids) {
        const getReq = store.get(id);
        getReq.onsuccess = () => {
            const row = getReq.result as StoredClientLogEntry | undefined;
            if (!row) return;
            row.shipped_at = shippedAt;
            store.put(row);
        };
    }
    await awaitTx(tx);
}

export async function getRecentClientLogs(limit: number): Promise<LogsResponse> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const index = tx.objectStore(STORE).index(INDEX_TIMESTAMP);
    const out: StoredClientLogEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = index.openCursor(null, 'prev');
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor || out.length >= limit) {
                const date = out[0]?.timestamp.slice(0, 10) ?? localDateToday();
                resolve({ date, entries: out.map(stripShipped), total: out.length });
                return;
            }
            out.push(cursor.value as StoredClientLogEntry);
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read client logs'));
    });
}

export async function queryClientLogs(
    filters: Pick<LogsQuery, 'level' | 'search'>,
    limit = DEFAULT_QUERY_LIMIT,
): Promise<LogsResponse> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const index = tx.objectStore(STORE).index(INDEX_TIMESTAMP);
    const allowed = filters.level && filters.level.length > 0 ? new Set(filters.level) : null;
    const needle = filters.search ? filters.search.toLowerCase() : null;
    const out: StoredClientLogEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = index.openCursor(null, 'prev');
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor || out.length >= limit) {
                const date = out[0]?.timestamp.slice(0, 10) ?? localDateToday();
                resolve({ date, entries: out.map(stripShipped), total: out.length });
                return;
            }
            const row = cursor.value as StoredClientLogEntry;
            if (allowed && !allowed.has(row.level)) {
                cursor.continue();
                return;
            }
            if (needle && !row.message.toLowerCase().includes(needle) && !row.module.toLowerCase().includes(needle)) {
                cursor.continue();
                return;
            }
            out.push(row);
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to query client logs'));
    });
}

export async function deleteAllClientLogs(): Promise<void> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).clear();
    await awaitTx(tx);
}

/** Test-only: close cached DB so a fresh `indexedDB` global can be substituted between tests. */
export function resetClientLogStoreForTests(): void {
    if (dbPromise) {
        void dbPromise.then((db) => db.close()).catch(() => undefined);
    }
    dbPromise = null;
}

function stripShipped(row: StoredClientLogEntry): ClientLogEntry {
    const { shipped_at: _, ...rest } = row;
    return rest;
}

function localDateToday(): string {
    return Temporal.Now.zonedDateTimeISO(APP_TIME_ZONE).toPlainDate().toString();
}
